function HowItWorks({ t }) {
  const [active, setActive] = useState(0);
  const timerRef = useRef(null);

  const startTimer = useCallback(() => {
    clearInterval(timerRef.current);
    timerRef.current = setInterval(() => setActive(s => (s + 1) % 4), 5000);
  }, []);

  useEffect(() => { startTimer(); return () => clearInterval(timerRef.current); }, [startTimer]);

  const steps = [
    {
      num: '01', emoji: '💬',
      h: t.step1_h, p: t.step1_p,
      bullets: [t.step1_b1, t.step1_b2, t.step1_b3],
      accent: '#5580cc',
    },
    {
      num: '02', emoji: '🎨',
      h: t.step2_h, p: t.step2_p,
      bullets: [t.step2_b1, t.step2_b2, t.step2_b3],
      accent: '#a78bfa',
    },
    {
      num: '03', emoji: '🌐',
      h: t.step3_h, p: t.step3_p,
      bullets: [t.step3_b1, t.step3_b2, t.step3_b3],
      accent: '#34d399',
    },
    {
      num: '04', emoji: '🚀',
      h: t.step4_h, p: t.step4_p,
      bullets: [t.step4_b1, t.step4_b2, t.step4_b3],
      accent: '#fbbf24',
    },
  ];

  const s = steps[active];

  return (
    <section id="how-we-work" style={{background:'#070b14', padding:'100px 60px'}}>
      <div style={{maxWidth:1020, margin:'0 auto'}}>

        <div className="section-header reveal" style={{textAlign:'center', marginBottom:56}}>
          <div className="section-label" style={{color:'var(--blue)'}}>{t.how_label}</div>
          <h2 className="section-title" style={{color:'#fff'}}>{t.how_h}</h2>
          <p className="section-sub" style={{color:'rgba(255,255,255,0.45)'}}>{t.how_sub}</p>
        </div>

        <div className="reveal" style={{display:'grid', gridTemplateColumns:'220px 1fr', gap:0, background:'rgba(255,255,255,0.03)', border:'1px solid rgba(255,255,255,0.07)', borderRadius:24, overflow:'hidden'}}>

          {/* LEFT: step tabs */}
          <div style={{borderRight:'1px solid rgba(255,255,255,0.07)', padding:'8px 0', display:'flex', flexDirection:'column'}}>
            {steps.map((step, i) => (
              <button
                key={i}
                onClick={() => { setActive(i); startTimer(); }}
                style={{
                  background: active === i ? 'rgba(85,128,204,0.1)' : 'transparent',
                  border: 'none',
                  borderLeft: `3px solid ${active === i ? step.accent : 'transparent'}`,
                  padding: '18px 20px',
                  cursor: 'pointer',
                  textAlign: 'left',
                  transition: 'all 0.25s',
                  position: 'relative',
                }}
              >
                <div style={{fontSize:'0.6rem', fontWeight:800, letterSpacing:'0.14em', color: active===i ? step.accent : 'rgba(255,255,255,0.25)', textTransform:'uppercase', marginBottom:5, fontFamily:'inherit'}}>
                  {step.num}
                </div>
                <div style={{fontSize:'0.82rem', fontWeight:700, color: active===i ? '#fff' : 'rgba(255,255,255,0.45)', lineHeight:1.3, fontFamily:'inherit'}}>
                  {step.h}
                </div>
                {/* progress bar at bottom of active tab */}
                {active === i && (
                  <div key={active} style={{position:'absolute', bottom:0, left:0, right:0, height:2, background:step.accent, animation:'stepProgress 5s linear forwards'}}/>
                )}
              </button>
            ))}
          </div>

          {/* RIGHT: content panel */}
          <div key={active} style={{padding:'40px 44px', animation:'panelIn 0.35s ease'}}>

            {/* Top: emoji + step label */}
            <div style={{display:'flex', alignItems:'center', gap:14, marginBottom:28}}>
              <div style={{width:56, height:56, borderRadius:16, background:`rgba(${hexToRgbStr(s.accent)},0.12)`, border:`1px solid rgba(${hexToRgbStr(s.accent)},0.25)`, display:'flex', alignItems:'center', justifyContent:'center', fontSize:'1.6rem', flexShrink:0}}>
                {s.emoji}
              </div>
              <div>
                <div style={{fontSize:'0.62rem', fontWeight:800, color:s.accent, letterSpacing:'0.16em', textTransform:'uppercase', marginBottom:4}}>
                  {t[`step_num_${active+1}`]}
                </div>
                <h3 style={{fontSize:'1.4rem', fontWeight:900, color:'#fff', letterSpacing:'-0.02em', lineHeight:1.1}}>
                  {s.h}
                </h3>
              </div>
            </div>

            {/* Description */}
            <p style={{fontSize:'0.95rem', color:'rgba(255,255,255,0.55)', lineHeight:1.78, marginBottom:28, maxWidth:480}}>
              {s.p}
            </p>

            {/* Bullets */}
            <div style={{display:'flex', flexDirection:'column', gap:12}}>
              {s.bullets.map((b,i) => (
                <div key={i} style={{display:'flex', alignItems:'flex-start', gap:12}}>
                  <div style={{width:22, height:22, borderRadius:7, background:`rgba(${hexToRgbStr(s.accent)},0.15)`, border:`1px solid rgba(${hexToRgbStr(s.accent)},0.3)`, display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0, marginTop:1}}>
                    <svg width="10" height="10" viewBox="0 0 10 10"><path d="M2 5l2.5 2.5L8 3" stroke={s.accent} strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round" fill="none"/></svg>
                  </div>
                  <span style={{fontSize:'0.88rem', color:'rgba(255,255,255,0.7)', lineHeight:1.6}}>{b}</span>
                </div>
              ))}
            </div>

            {/* Bottom badge */}
            <div style={{marginTop:36, paddingTop:28, borderTop:'1px solid rgba(255,255,255,0.06)', display:'flex', alignItems:'center', justifyContent:'space-between'}}>
              <div style={{display:'flex', gap:8}}>
                {steps.map((_,i) => (
                  <div key={i} style={{width: i===active ? 24 : 8, height:8, borderRadius:4, background: i===active ? s.accent : 'rgba(255,255,255,0.12)', transition:'all 0.3s'}}/>
                ))}
              </div>
              <div style={{display:'inline-flex', alignItems:'center', gap:8, background:`rgba(${hexToRgbStr(s.accent)},0.1)`, border:`1px solid rgba(${hexToRgbStr(s.accent)},0.2)`, borderRadius:50, padding:'7px 16px'}}>
                <span style={{fontSize:'0.75rem', fontWeight:700, color:s.accent}}>{t.how_badge}</span>
              </div>
            </div>

          </div>
        </div>

      </div>
      <style>{`
        @keyframes stepProgress { from{width:0} to{width:100%} }
        @keyframes panelIn { from{opacity:0;transform:translateY(8px)} to{opacity:1;transform:translateY(0)} }
        @media(max-width:700px){
          #how-we-work > div > div.reveal { grid-template-columns: 1fr !important; }
          #how-we-work > div > div.reveal > div:first-child { border-right: none !important; border-bottom: 1px solid rgba(255,255,255,0.07); flex-direction: row !important; overflow-x: auto; padding: 0 !important; }
          #how-we-work > div > div.reveal > div:first-child button { border-left: none !important; border-bottom: 3px solid transparent; flex-shrink: 0; min-width: 120px; }
          #how-we-work > div > div.reveal > div:last-child { padding: 28px 20px !important; }
        }
      `}</style>
    </section>
  );
}

function hexToRgbStr(hex) {
  const n = parseInt(hex.replace('#',''), 16);
  return `${n>>16},${(n>>8)&0xff},${n&0xff}`;
}

