            <div style={{position:"absolute",top:-140,right:-140,width:500,height:500,borderRadius:"50%",background:`radial-gradient(circle,rgba(${rgb(color)},0.14),transparent 70%)`,filter:"blur(30px)",transition:"background 0.5s"}}/>
